import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/controllers/locale_controller.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/locale_ext.dart';
import 'package:baseball_detector_flutter/utils/web_url.dart';

/// チーム向けプラン案内
class OrganizationPlanRecommendContainer extends HookConsumerWidget {
  const OrganizationPlanRecommendContainer({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final locale = ref.watch(localeControllerProvider);
    final isJapanese = locale.isJapanese;

    final theme = Theme.of(context);
    // return GestureDetector(
    //   onTap: () async {
    //     final teamPlanUrl = isJapanese
    //         ? Constants.organizationPlanURLJa
    //         : Constants.organizationPlanURL;
    //     await openURLWithSystemBrowser(url: teamPlanUrl);
    //   },
    //   child: Container(
    //     decoration: BoxDecoration(
    //       borderRadius: BorderRadius.circular(16),
    //     ),

    return ElevatedButton(
      onPressed: () async {
        final teamPlanUrl = isJapanese
            ? Constants.organizationPlanURLJa
            : Constants.organizationPlanURL;
        await openURLWithSystemBrowser(url: teamPlanUrl);
      },
      style: ElevatedButton.styleFrom(
        backgroundColor: theme.colorScheme.surface,
        disabledBackgroundColor: theme.colorScheme.surfaceDim,
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(12),
        ),
        shadowColor: null,
        padding: EdgeInsets.all(0),
        elevation: 2,
      ),
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: [
            Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(
                  children: [
                    Icon(
                      Icons.open_in_new,
                      size: 18,
                      color: theme.colorScheme.primary,
                    ),
                    const Gap(8),
                    Column(
                      children: [
                        Text(
                          context.l10n.subscription_page__team_plan_info,
                          style: theme.textTheme.titleLarge?.copyWith(
                            fontWeight: FontWeight.bold,
                            fontSize: 18,
                          ),
                        ),
                        const Gap(2),
                      ],
                    ),
                  ],
                ),
                Text(
                  context.l10n.subscription_page__team_plan_description,
                  style: theme.textTheme.bodySmall?.copyWith(
                    color: theme.colorScheme.onSurfaceVariant,
                  ),
                ),
              ],
            ),
            Icon(
              Icons.chevron_right,
              size: 18,
              color: theme.colorScheme.primary,
            ),
          ],
        ),
      ),
    );
  }
}

